EMPTY, TOMBSTONE = None, '__DELETED__'

class LinearProbingTable:
    def __init__(self, capacity=16):
        self.cap   = capacity
        self.table = [EMPTY] * capacity

    def _hash(self, key): return hash(key) % self.cap

    def put(self, key, value):
        idx = self._hash(key)
        first_tomb = None
        for _ in range(self.cap):
            cell = self.table[idx]
            if cell is EMPTY:
                pos = first_tomb if first_tomb is not None else idx
                self.table[pos] = (key, value)
                return
            if cell is TOMBSTONE:
                if first_tomb is None: first_tomb = idx
            elif cell[0] == key:
                self.table[idx] = (key, value); return
            idx = (idx + 1) % self.cap

    def get(self, key):
        idx = self._hash(key)
        for _ in range(self.cap):
            cell = self.table[idx]
            if cell is EMPTY:
                raise KeyError(key)       # end of probe chain
            if cell is not TOMBSTONE and ___________:
                return cell[1]
            idx = (idx + 1) % self.cap
        raise KeyError(key)

    def delete(self, key):
        idx = self._hash(key)
        for _ in range(self.cap):
            cell = self.table[idx]
            if cell is EMPTY: raise KeyError(key)
            if cell is not TOMBSTONE and cell[0] == key:
                self.table[idx] = TOMBSTONE; return
            idx = (idx + 1) % self.cap
        raise KeyError(key)
